document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("wheel_photos"),t=document.getElementById("fileList");!e||!t||e.addEventListener("change",()=>{t.innerHTML="",e.files.length&&Array.from(e.files).forEach(i=>{const n=document.createElement("div");n.className="file-item",n.textContent=i.name,t.appendChild(n)})})});
